import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import api from "../api/axios";
import "./Admin.css";

export default function AdminPanel() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [users, setUsers] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [usersRes, statsRes] = await Promise.all([
        api.get("/admin/users"),
        api.get("/admin/stats"),
      ]);
      setUsers(usersRes.data.data.users);
      setStats(statsRes.data.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleRoleChange = async (id, role) => {
    try {
      await api.patch(`/admin/users/${id}/role`, { role });
      fetchData();
    } catch (err) {
      alert(err.response?.data?.message || "Failed");
    }
  };

  const handleToggleStatus = async (id) => {
    try {
      await api.patch(`/admin/users/${id}/status`);
      fetchData();
    } catch (err) {
      alert(err.response?.data?.message || "Failed");
    }
  };

  const handleLogout = async () => {
    await logout();
    navigate("/login");
  };

  const filtered = users.filter(
    (u) =>
      u.name.toLowerCase().includes(search.toLowerCase()) ||
      u.email.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="admin-container">
      <div className="admin-bg" />

      <nav className="admin-nav">
        <div className="admin-nav-logo">⬡ SecureAuth <span>Admin</span></div>
        <div className="admin-nav-right">
          <button className="nav-dash-btn" onClick={() => navigate("/dashboard")}>Dashboard</button>
          <div className="nav-avatar">{user?.name?.[0]?.toUpperCase()}</div>
          <button className="nav-logout" onClick={handleLogout}>Sign out</button>
        </div>
      </nav>

      <main className="admin-main">
        <div className="admin-hero">
          <h1>Admin <span>Panel</span></h1>
          <p>Manage users, roles, and access control</p>
        </div>

        {stats && (
          <div className="stats-grid">
            <div className="stat-card">
              <div className="stat-icon">👥</div>
              <div className="stat-num">{stats.totalUsers}</div>
              <div className="stat-label">Total Users</div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">👑</div>
              <div className="stat-num">{stats.totalAdmins}</div>
              <div className="stat-label">Admins</div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">✅</div>
              <div className="stat-num">{stats.activeUsers}</div>
              <div className="stat-label">Active</div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">🆕</div>
              <div className="stat-num">{stats.newUsersToday}</div>
              <div className="stat-label">New Today</div>
            </div>
          </div>
        )}

        <div className="admin-table-section">
          <div className="table-header">
            <h2>Users</h2>
            <input
              className="search-input"
              placeholder="Search by name or email..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          {loading ? (
            <div className="table-loading">Loading...</div>
          ) : (
            <div className="table-wrap">
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>User</th>
                    <th>Role</th>
                    <th>Status</th>
                    <th>Joined</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((u) => (
                    <tr key={u.id}>
                      <td>
                        <div className="user-cell">
                          <div className="user-avatar">{u.name[0].toUpperCase()}</div>
                          <div>
                            <div className="user-name">{u.name}</div>
                            <div className="user-email">{u.email}</div>
                          </div>
                        </div>
                      </td>
                      <td>
                        <span className={`role-badge ${u.role.toLowerCase()}`}>{u.role}</span>
                      </td>
                      <td>
                        <span className={`status-badge ${u.isActive ? "active" : "inactive"}`}>
                          {u.isActive ? "Active" : "Disabled"}
                        </span>
                      </td>
                      <td className="date-cell">
                        {new Date(u.createdAt).toLocaleDateString()}
                      </td>
                      <td>
                        <div className="action-btns">
                          {u.id !== user.id && (
                            <>
                              <button
                                className="action-btn role-btn"
                                onClick={() => handleRoleChange(u.id, u.role === "ADMIN" ? "USER" : "ADMIN")}
                              >
                                {u.role === "ADMIN" ? "→ User" : "→ Admin"}
                              </button>
                              <button
                                className={`action-btn ${u.isActive ? "disable-btn" : "enable-btn"}`}
                                onClick={() => handleToggleStatus(u.id)}
                              >
                                {u.isActive ? "Disable" : "Enable"}
                              </button>
                            </>
                          )}
                          {u.id === user.id && <span className="you-badge">You</span>}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
